final:
module RefModule (
    input wire clk,
    input wire signal,
    output reg edge_detected
);

reg signal_prev;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    signal_prev <= signal;
    edge_detected <= (signal && ~signal_prev);
end

endmodule
